export function relatedProjects({
	env = process.env,
	noThrow = false,
}: RelatedProjectsOptions = {}): RelatedProject[] {
	const value = env.VERCEL_RELATED_PROJECTS;
	if (!value) {
		if (noThrow) {
			return [];
